// Validação HMAC-SHA256 do header X-Signature.
// O segredo está em $env.N8N_WEBHOOK_SECRET (configure no n8n).
const crypto = require('crypto');

const secret  = $env.N8N_WEBHOOK_SECRET || '';
const given   = ($input.first().json.headers || {})['x-signature'] || '';
// O 'rawBody' fica em $input.first().binary?.data — usamos o body bruto:
const rawBody = $input.first().json.body ? JSON.stringify($input.first().json.body) : '';

// Recalcula com os mesmos separadores que o SIGE usa (separators=(',',':'))
// — se o n8n estiver configurado com 'rawBody=true' no Webhook node,
// o corpo bruto vem em $input.first().binary.data (Buffer).
let bodyForHmac = rawBody;
try {
  if ($input.first().binary && $input.first().binary.data) {
    bodyForHmac = Buffer.from($input.first().binary.data, 'base64').toString('utf8');
  }
} catch (e) {}

if (!secret) {
  return [{ json: { ...$input.first().json, _signature_ok: true, _signature_skipped: 'no_secret' } }];
}

const expected = crypto.createHmac('sha256', secret).update(bodyForHmac, 'utf8').digest('hex');
const ok = expected.length === given.length
  && crypto.timingSafeEqual(Buffer.from(expected), Buffer.from(given));

if (!ok) {
  throw new Error('Assinatura HMAC inválida (X-Signature não confere)');
}
return [{ json: { ...$input.first().json, _signature_ok: true } }];

// Normaliza o payload — extrai dados do evento `proposta.enviada`.
const body = $input.first().json.body || $input.first().json;
const d = (body && body.data) || {};

return [{
  json: {
    cliente_nome:     d.cliente_nome     || 'Cliente',
    cliente_email:    d.cliente_email    || '',
    cliente_telefone: d.cliente_telefone || '',
    proposta_numero:  d.proposta_numero  || d.numero || '',
    proposta_versao:  d.proposta_versao  || d.versao || 1,
    valor_total:      d.valor_total      || 0,
    validade_dias:    d.validade_dias    || 7,
    portal_url:       d.portal_url       || '',
    admin_id:         body.admin_id      || null,
    occurred_at:      body.occurred_at   || null
  }
}];

